namespace sv_3e10ae7cc395439c8b52fc66db03a620.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

.channel-item {
    display: flex;
    align-items: center;
    padding: 6px 12px;
    cursor: pointer;
    border-radius: 4px;
    margin: 1px 8px;
    transition: background-color 0.15s;
}

.channel-item:hover {
    background: rgba(255, 255, 255, 0.08);
}

.channel-item.active {
    background: rgba(255, 255, 255, 0.15);
    font-weight: 600;
}

.channel-info {
    flex: 1;
    min-width: 0;
}

.channel-name {
    font-size: 0.9rem;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.hash {
    color: #8e9297;
    margin-right: 2px;
}

.channel-description {
    font-size: 0.75rem;
    color: #8e9297;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    margin-top: 1px;
}

.unread-badge {
    background: #ed4245;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 1px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
    flex-shrink: 0;
    margin-left: 8px;
}

.channel-sidebar {
    width: 260px;
    min-width: 220px;
    background: #2b2d31;
    color: #f2f3f5;
    display: flex;
    flex-direction: column;
    border-right: 1px solid #1e1f22;
    height: 100%;
}

.sidebar-header {
    padding: 16px;
    border-bottom: 1px solid #1e1f22;
}

.sidebar-header h3 {
    margin: 0;
    font-size: 1rem;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    color: #b5bac1;
}

.channel-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.message-item {
    padding: 8px 16px;
    position: relative;
    border-radius: 4px;
    transition: background-color 0.1s;
}

.message-item:hover {
    background: #f2f3f5;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.message-author {
    font-weight: 600;
    font-size: 0.95rem;
    color: #111;
}

.message-time {
    font-size: 0.75rem;
    color: #5c6370;
}

.message-content {
    font-size: 0.9rem;
    color: #2e3338;
    line-height: 1.4;
    white-space: pre-wrap;
    word-break: break-word;
}

.reaction-row {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    background: #e3e5e8;
    border: 1px solid #d3d5d9;
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 0.8rem;
    cursor: pointer;
    transition: background-color 0.15s;
}

.reaction-badge:hover {
    background: #c8ccd1;
}

.thread-link {
    display: inline-block;
    margin-top: 4px;
    font-size: 0.8rem;
    color: #1264a3;
    background: none;
    border: none;
    cursor: pointer;
    padding: 2px 0;
    font-weight: 500;
}

.thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: -12px;
    right: 16px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #d3d5d9;
    border-radius: 6px;
    padding: 2px;
    box-shadow: 0 1px 4px rgba(0, 0, 0, 0.1);
    z-index: 10;
}

.action-btn {
    background: none;
    border: none;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
    font-size: 1rem;
    line-height: 1;
    transition: background-color 0.15s;
}

.action-btn:hover {
    background: #e3e5e8;
}

.emoji-picker {
    position: absolute;
    top: -12px;
    right: 90px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #d3d5d9;
    border-radius: 8px;
    padding: 4px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
    z-index: 20;
}

.emoji-option {
    background: none;
    border: none;
    cursor: pointer;
    padding: 4px 6px;
    border-radius: 4px;
    font-size: 1.2rem;
    line-height: 1;
    transition: background-color 0.15s;
}

.emoji-option:hover {
    background: #e3e5e8;
}

.message-input-container {
    display: flex;
    align-items: flex-end;
    gap: 8px;
    padding: 12px 16px;
    border-top: 1px solid #e3e5e8;
    background: #fff;
}

.message-textarea {
    flex: 1;
    resize: none;
    border: 1px solid #d3d5d9;
    border-radius: 8px;
    padding: 10px 12px;
    font-size: 0.9rem;
    font-family: inherit;
    outline: none;
    min-height: 40px;
    max-height: 120px;
    line-height: 1.4;
}

.message-textarea:focus {
    border-color: #1264a3;
    box-shadow: 0 0 0 2px rgba(18, 100, 163, 0.2);
}

.send-button {
    background: #1264a3;
    color: #fff;
    border: none;
    border-radius: 8px;
    padding: 10px 20px;
    font-size: 0.9rem;
    font-weight: 600;
    cursor: pointer;
    white-space: nowrap;
    transition: background-color 0.15s;
}

.send-button:hover:not(:disabled) {
    background: #0d4f82;
}

.send-button:disabled {
    background: #a0c4e4;
    cursor: not-allowed;
}

