toolArgs.file_text:
.message-item {
    padding: 8px 16px;
    position: relative;
    border-radius: 4px;
    transition: background-color 0.1s;
}

.message-item:hover {
    background: #f2f3f5;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.message-author {
    font-weight: 600;
    font-size: 0.95rem;
    color: #111;
}

.message-time {
    font-size: 0.75rem;
    color: #5c6370;
}

.message-content {
    font-size: 0.9rem;
    color: #2e3338;
    line-height: 1.4;
    white-space: pre-wrap;
    word-break: break-word;
}

.reaction-row {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    background: #e3e5e8;
    border: 1px solid #d3d5d9;
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 0.8rem;
    cursor: pointer;
    transition: background-color 0.15s;
}

.reaction-badge:hover {
    background: #c8ccd1;
}

.thread-link {
    display: inline-block;
    margin-top: 4px;
    font-size: 0.8rem;
    color: #1264a3;
    background: none;
    border: none;
    cursor: pointer;
    padding: 2px 0;
    font-weight: 500;
}

.thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: -12px;
    right: 16px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #d3d5d9;
    border-radius: 6px;
    padding: 2px;
    box-shadow: 0 1px 4px rgba(0, 0, 0, 0.1);
    z-index: 10;
}

.action-btn {
    background: none;
    border: none;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
    font-size: 1rem;
    line-height: 1;
    transition: background-color 0.15s;
}

.action-btn:hover {
    background: #e3e5e8;
}

.emoji-picker {
    position: absolute;
    top: -12px;
    right: 90px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #d3d5d9;
    border-radius: 8px;
    padding: 4px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
    z-index: 20;
}

.emoji-option {
    background: none;
    border: none;
    cursor: pointer;
    padding: 4px 6px;
    border-radius: 4px;
    font-size: 1.2rem;
    line-height: 1;
    transition: background-color 0.15s;
}

.emoji-option:hover {
    background: #e3e5e8;
}

