@implements IAsyncDisposable
@inject IJSRuntime JS

<div class="message-area">
    <div class="message-area-header">
        @if (CurrentChannel is not null)
        {
            <h2># @CurrentChannel.Name</h2>
            <span class="header-description">@CurrentChannel.Description</span>
        }
    </div>

    <div class="message-list" @ref="_messageListRef">
        @if (HasMoreMessages)
        {
            <button class="load-more-btn" @onclick="HandleLoadMore" disabled="@_isLoadingMore">
                @(_isLoadingMore ? "Loading…" : "↑ Load older messages")
            </button>
        }

        @foreach (var message in Messages)
        {
            <MessageItem Message="message"
                         ThreadSummary="GetThreadSummary(message.Id)"
                         OnOpenThread="OnOpenThread"
                         OnReact="OnReact" />
        }
    </div>

    <MessageInput Placeholder="@($"Message #{CurrentChannel?.Name ?? "channel"}")"
                  ButtonText="Send"
                  OnSend="OnSendMessage" />
</div>

@code {
    [Parameter] public Channel? CurrentChannel { get; set; }
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public List<ThreadSummary> ThreadSummaries { get; set; } = [];
    [Parameter] public bool HasMoreMessages { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }

    private ElementReference _messageListRef;
    private IJSObjectReference? _jsModule;
    private bool _isLoadingMore;
    private int? _previousChannelId;

    private ThreadSummary? GetThreadSummary(int messageId) =>
        ThreadSummaries.FirstOrDefault(t => t.RootMessageId == messageId);

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _jsModule = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./Components/Chat/MessageArea.razor.js");
        }

        if (CurrentChannel is not null && _previousChannelId != CurrentChannel.Id)
        {
            _previousChannelId = CurrentChannel.Id;
            if (_jsModule is not null)
            {
                await _jsModule.InvokeVoidAsync("scrollToBottom", _messageListRef);
            }
        }
    }

    private async Task HandleLoadMore()
    {
        if (_isLoadingMore) return;
        _isLoadingMore = true;

        double previousScrollHeight = 0;
        if (_jsModule is not null)
        {
            previousScrollHeight = await _jsModule.InvokeAsync<double>("getScrollHeight", _messageListRef);
        }

        await OnLoadMore.InvokeAsync();
        _isLoadingMore = false;

        // Preserve scroll position after older messages are prepended
        if (_jsModule is not null && previousScrollHeight > 0)
        {
            await Task.Yield();
            await _jsModule.InvokeVoidAsync("preserveScrollPosition", _messageListRef, previousScrollHeight);
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_jsModule is not null)
        {
            await _jsModule.DisposeAsync();
        }
    }
}

.message-area {
    flex: 1;
    display: flex;
    flex-direction: column;
    min-width: 0;
    height: 100%;
    background: #fff;
}

.message-area-header {
    padding: 12px 16px;
    border-bottom: 1px solid #e3e5e8;
