{"file_text": "export function scrollToBottom(element) {
    if (element) {
        element.scrollTop = element.scrollHeight;
    }
}

export function getScrollHeight(element) {
    return element ? element.scrollHeight : 0;
}

export function preserveScrollPosition(element, previousScrollHeight) {
    if (element) {
        const newScrollHeight = element.scrollHeight;
        element.scrollTop = newScrollHeight - previousScrollHeight;
    }
}
