    margin: 0;
    font-size: 1rem;
    font-weight: 700;
}

.close-btn {
    background: none;
    border: none;
    font-size: 1.1rem;
    cursor: pointer;
    color: #616061;
    padding: 4px 8px;
    border-radius: 4px;
    line-height: 1;
    transition: background-color 0.15s;
