.root-author {
    font-weight: 600;
    font-size: 0.9rem;
    margin-bottom: 4px;
}

.root-content {
    font-size: 0.85rem;
    color: #2e3338;
    line-height: 1.4;
}

.thread-divider {
    padding: 8px 16px;
    font-size: 0.75rem;
    color: #616061;
    border-bottom: 1px solid #e3e5e8;
    flex-shrink: 0;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 4px 0;
}

.thread-reply {
    padding: 8px 16px;
