toolArgs.file_text:
@page "/chat"
@rendermode InteractiveServer
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <ChannelSidebar Channels="_channels"
                    SelectedChannelId="_selectedChannel?.Id"
                    OnChannelSelected="HandleChannelSelected" />

    <MessageArea CurrentChannel="_selectedChannel"
                 Messages="_messages"
                 ThreadSummaries="_threadSummaries"
                 HasMoreMessages="_hasMoreMessages"
                 OnLoadMore="HandleLoadMore"
                 OnOpenThread="HandleOpenThread"
                 OnReact="HandleReact"
                 OnSendMessage="HandleSendMessage" />

    @if (_isThreadOpen && _threadRootMessage is not null)
    {
        <ThreadPanel RootMessage="_threadRootMessage"
                     ThreadMessages="_threadMessages"
                     OnClose="HandleCloseThread"
                     OnSendReply="HandleSendReply" />
    }
</div>

@code {
    private List<Channel> _channels = [];
    private Channel? _selectedChannel;
    private List<Message> _messages = [];
    private List<ThreadSummary> _threadSummaries = [];
    private bool _hasMoreMessages = true;
    private const int PageSize = 30;

    private bool _isThreadOpen;
    private Message? _threadRootMessage;
    private List<Message> _threadMessages = [];

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
        {
            await SelectChannel(_channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        _selectedChannel = _channels.FirstOrDefault(c => c.Id == channelId);
        if (_selectedChannel is null) return;

        _messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        _hasMoreMessages = _messages.Count >= PageSize;
        _threadSummaries = BuildThreadSummaries(_messages);

        await ChatService.MarkChannelReadAsync(channelId);

        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            _channels[idx] = _channels[idx] with { UnreadCount = 0 };
        }

        _isThreadOpen = false;
        _threadRootMessage = null;
        _threadMessages = [];
    }

    private async Task HandleChannelSelected(int channelId) =>
        await SelectChannel(channelId);

    private async Task HandleLoadMore()
    {
        if (_selectedChannel is null) return;

        var older = await ChatService.GetMessagesAsync(_selectedChannel.Id, _messages.Count, PageSize);
        if (older.Count < PageSize)
        {
            _hasMoreMessages = false;
        }

        _messages.InsertRange(0, older);
        _threadSummaries = BuildThreadSummaries(_messages);
    }

    private async Task HandleOpenThread(int messageId)
    {
        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == messageId);
        if (_threadRootMessage is null) return;

        _threadMessages = await ChatService.GetThreadAsync(messageId);
        _isThreadOpen = true;
    }

    private async Task HandleReact((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        if (_selectedChannel is not null)
        {
            _messages = await ChatService.GetMessagesAsync(_selectedChannel.Id, 0, _messages.Count);
        }
    }

    private async Task HandleSendMessage(string content)
    {
        if (_selectedChannel is null) return;

        var msg = await ChatService.SendMessageAsync(_selectedChannel.Id, content, null);
        _messages.Add(msg);
    }

    private async Task HandleSendReply(string content)
    {
        if (_selectedChannel is null || _threadRootMessage is null) return;

        var reply = await ChatService.SendMessageAsync(_selectedChannel.Id, content, _threadRootMessage.Id);
        _threadMessages.Add(reply);

        // Update thread summary for the root message
        var existing = _threadSummaries.FindIndex(t => t.RootMessageId == _threadRootMessage.Id);
        var updated = new ThreadSummary(_threadRootMessage.Id, _threadMessages.Count, reply.SentAt);
        if (existing >= 0)
            _threadSummaries[existing] = updated;
        else
            _threadSummaries.Add(updated);
    }

    private void HandleCloseThread()
    {
        _isThreadOpen = false;
